CREATE TABLE quote_sequences(tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),year integer NOT NULL,value integer NOT NULL CHECK(value>=1),PRIMARY KEY(tenant_id,organization_id,year));
CREATE TABLE quotes(id uuid PRIMARY KEY,tenant_id uuid NOT NULL REFERENCES tenants(id),organization_id uuid NOT NULL REFERENCES organizations(id),site_id uuid NOT NULL REFERENCES sites(id),customer_id uuid NOT NULL REFERENCES customers(id),asset_id uuid REFERENCES assets(id),opportunity_id uuid REFERENCES crm_opportunities(id),number text NOT NULL,version integer NOT NULL CHECK(version>=1),currency char(3) NOT NULL,lines jsonb NOT NULL CHECK(jsonb_typeof(lines)='array'),subtotal_cents integer NOT NULL,discount_cents integer NOT NULL,tax_cents integer NOT NULL,total_cents integer NOT NULL,status text NOT NULL CHECK(status IN('draft','sent','accepted','rejected','expired','cancelled')),valid_until timestamptz NOT NULL,terms_hash char(64) NOT NULL,created_by uuid NOT NULL,created_at timestamptz NOT NULL,sent_at timestamptz,accepted_at timestamptz,accepted_by_customer_id uuid REFERENCES customers(id),UNIQUE(tenant_id,organization_id,number,version));
CREATE INDEX quotes_customer_idx ON quotes(tenant_id,customer_id,created_at DESC);
CREATE INDEX quotes_status_idx ON quotes(tenant_id,organization_id,status,valid_until);
DO $$ DECLARE n text;BEGIN FOREACH n IN ARRAY ARRAY['quote_sequences','quotes'] LOOP EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY',n);EXECUTE format('ALTER TABLE %I FORCE ROW LEVEL SECURITY',n);EXECUTE format('CREATE POLICY tenant_isolation ON %I USING (tenant_id=current_setting(''app.tenant_id'',true)::uuid) WITH CHECK (tenant_id=current_setting(''app.tenant_id'',true)::uuid)',n);END LOOP;END $$;
